const COUNTRY_NAMES: Record<string, string> = {
  US: 'United States',
  GB: 'United Kingdom',
  DE: 'Germany',
  FR: 'France',
  JP: 'Japan',
  CN: 'China',
  IN: 'India',
  BR: 'Brazil',
  AU: 'Australia',
  CA: 'Canada',
}

export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

export function geoFromHeaders(headers: Headers): Geo {
  const countryCode =
    headers.get('x-vercel-ip-country') ??
    headers.get('cf-ipcountry') ??
    undefined

  return {
    city: headers.get('x-vercel-ip-city') ?? undefined,
    countryCode,
    country: countryCode
      ? COUNTRY_NAMES[countryCode.toUpperCase()]
      : undefined,
    region: headers.get('x-vercel-ip-country-region') ?? undefined,
    latitude: headers.get('x-vercel-ip-latitude') ?? undefined,
    longitude: headers.get('x-vercel-ip-longitude') ?? undefined,
    timezone: headers.get('x-vercel-ip-timezone') ?? undefined,
  }
}

export function geo(req: { headers: Headers }): Geo {
  return geoFromHeaders(req.headers)
}

export function isInRegion(geoData: Geo, regions: string[]): boolean {
  if (!geoData.countryCode) return false
  const code = geoData.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

function toRad(deg: number): number {
  return deg * (Math.PI / 180)
}

export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371
  const phi1 = parseFloat(lat1)
  const phi2 = parseFloat(lat2)
  const dPhi = toRad(phi2 - phi1)
  const dLambda = toRad(parseFloat(lon2) - parseFloat(lon1))
  const a =
    Math.sin(dPhi / 2) ** 2 +
    Math.cos(toRad(phi1)) * Math.cos(toRad(phi2)) * Math.sin(dLambda / 2) ** 2
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
}

