import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

describe('geo()', () => {
  it('extracts all fields from Vercel headers', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'San Francisco',
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'CA',
      'x-vercel-ip-latitude': '37.7749',
      'x-vercel-ip-longitude': '-122.4194',
      'x-vercel-ip-timezone': 'America/Los_Angeles',
    })

    expect(geo({ headers })).toStrictEqual({
      city: 'San Francisco',
      countryCode: 'US',
      country: 'United States',
      region: 'CA',
      latitude: '37.7749',
      longitude: '-122.4194',
      timezone: 'America/Los_Angeles',
    })
  })

  it('returns undefined fields when no headers are present', () => {
    const headers = new Headers()

    expect(geo({ headers })).toStrictEqual({
      city: undefined,
      countryCode: undefined,
      country: undefined,
      region: undefined,
      latitude: undefined,
      longitude: undefined,
      timezone: undefined,
    })
  })
})

describe('geoFromHeaders()', () => {
  it('uses cf-ipcountry as fallback when x-vercel-ip-country is absent', () => {
    const headers = new Headers({
      'cf-ipcountry': 'GB',
      'x-vercel-ip-city': 'London',
    })

    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('GB')
    expect(result.country).toBe('United Kingdom')
    expect(result.city).toBe('London')
  })

  it('prefers x-vercel-ip-country over cf-ipcountry', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'DE',
      'cf-ipcountry': 'FR',
    })

    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('DE')
    expect(result.country).toBe('Germany')
  })

  it('derives country name for known country codes', () => {
    const codes: Array<[string, string]> = [
      ['US', 'United States'],
      ['GB', 'United Kingdom'],
      ['DE', 'Germany'],
      ['FR', 'France'],
      ['JP', 'Japan'],
      ['CN', 'China'],
      ['IN', 'India'],
      ['BR', 'Brazil'],
      ['AU', 'Australia'],
      ['CA', 'Canada'],
    ]

    for (const [code, name] of codes) {
      const headers = new Headers({ 'x-vercel-ip-country': code })
      const result = geoFromHeaders(headers)
      expect(result.countryCode).toBe(code)
      expect(result.country).toBe(name)
    }
  })

  it('returns undefined country for unknown country code', () => {
    const headers = new Headers({ 'x-vercel-ip-country': 'ZZ' })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('ZZ')
    expect(result.country).toBeUndefined()
  })
})

describe('isInRegion()', () => {
  it('returns true when countryCode matches a region (case-insensitive)', () => {
    expect(isInRegion({ countryCode: 'US' }, ['US', 'CA'])).toBe(true)
    expect(isInRegion({ countryCode: 'us' }, ['US', 'CA'])).toBe(true)
    expect(isInRegion({ countryCode: 'US' }, ['us', 'ca'])).toBe(true)
  })

  it('returns false when countryCode does not match any region', () => {
    expect(isInRegion({ countryCode: 'DE' }, ['US', 'CA'])).toBe(false)
  })

  it('returns false when countryCode is undefined', () => {
    expect(isInRegion({}, ['US', 'CA'])).toBe(false)
  })

  it('returns false for an empty regions list', () => {
    expect(isInRegion({ countryCode: 'US' }, [])).toBe(false)
  })
})

describe('geoDistance()', () => {
  it('calculates distance between New York and London within 50 km tolerance', () => {
    // New York: 40.7128°N, 74.0060°W
    // London:   51.5074°N,  0.1278°W
    // Expected: ~5570 km
    const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    expect(dist).toBeGreaterThan(5520)
    expect(dist).toBeLessThan(5620)
  })

  it('returns 0 for identical coordinates', () => {
    const dist = geoDistance('48.8566', '2.3522', '48.8566', '2.3522')
    expect(dist).toBeCloseTo(0, 5)
  })

  it('calculates a short distance correctly', () => {
    // Sydney to Melbourne: ~714 km
    const dist = geoDistance('-33.8688', '151.2093', '-37.8136', '144.9631')
    expect(dist).toBeGreaterThan(680)
    expect(dist).toBeLessThan(750)
  })
})

